import React from 'react';
import { motion } from 'framer-motion';
import { Rocket, Shield, Users, Search, LayoutDashboard, ArrowRight } from 'lucide-react';
import { Link } from 'react-router-dom';
import Navbar from '../components/Navbar';
import { useAuth } from '../context/AuthContext';

const Home = () => {
  const { user, token } = useAuth();
  const isLoggedIn = !!token && !!user;

  return (
    <div className="relative min-h-screen pt-24 overflow-hidden">
      <Navbar />

      {/* Background Orbs */}
      <div className="absolute top-20 left-10 w-96 h-96 bg-primary-600/30 blur-[150px] -z-10 rounded-full animate-float"></div>
      <div className="absolute bottom-10 right-10 w-96 h-96 bg-blue-600/20 blur-[150px] -z-10 rounded-full animate-float" style={{ animationDelay: '2s' }}></div>

      {/* Hero Section */}
      <section className="container mx-auto px-6 py-20 text-center relative z-10">
        <motion.div 
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          className="max-w-4xl mx-auto"
        >
          <span className="inline-block px-4 py-1.5 bg-primary-600/20 border border-primary-500/30 rounded-full text-primary-300 text-sm font-bold tracking-widest uppercase mb-6 animate-fade-in shadow-2xl">
            Empowering Campus Life 🚀
          </span>
          <h1 className="text-6xl md:text-8xl font-black mb-6 leading-tight font-poppins tracking-tighter shadow-2xl">
            Find Your Perfect <br/> 
            <span className="gradient-text">Campus Buddy</span>
          </h1>
          <p className="text-xl text-gray-400 mb-10 max-w-2xl mx-auto leading-relaxed italic opacity-80 uppercase tracking-widest text-sm">
            Collaborate, grow, and build meaningful connections within your campus. 
          </p>

          <div className="flex flex-col sm:flex-row items-center justify-center space-y-4 sm:space-y-0 sm:space-x-6">
            {isLoggedIn ? (
              <Link to="/dashboard" className="btn-primary flex items-center shadow-2xl text-lg font-bold uppercase tracking-widest">
                Go to Dashboard <LayoutDashboard size={20} className="ml-2" />
              </Link>
            ) : (
              <Link to="/signup" className="btn-primary flex items-center shadow-2xl text-lg font-bold uppercase tracking-widest">
                Get Started Now <Rocket size={20} className="ml-2" />
              </Link>
            )}

            <Link to="/find-buddies" className="btn-secondary flex items-center shadow-xl text-lg font-bold uppercase tracking-widest">
              Explore Buddies <Search size={20} className="ml-2" />
            </Link>
          </div>
        </motion.div>
      </section>

      {/* Features Grid */}
      <section className="container mx-auto px-6 py-20 pb-40">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-10">
          <FeatureCard 
            icon={Users} 
            title="Skill Sharing" 
            desc="Connect with peers who possess the skills you need or want to learn." 
          />
          <FeatureCard 
            icon={LayoutDashboard} 
            title="Smart Matching" 
            desc="Our algorithms help you find the most compatible buddies for your goals." 
            delay={0.2}
          />
          <FeatureCard 
            icon={Shield} 
            title="Campus Shield" 
            desc="Built-in emergency systems keeping you safe and connected 24/7." 
            delay={0.4}
          />
        </div>
      </section>

      {/* Footer */}
      <footer className="w-full py-10 glass border-t-0 shadow-2xl text-center">
        <p className="text-gray-500 text-sm font-black tracking-wider uppercase opacity-60">
          © 2025 BuddyUp Platform · Built for the Next Generation of Students
        </p>
      </footer>
    </div>
  );
};

const FeatureCard = ({ icon: Icon, title, desc, delay = 0 }) => (
  <motion.div 
    initial={{ opacity: 0, y: 50 }}
    whileInView={{ opacity: 1, y: 0 }}
    viewport={{ once: true }}
    transition={{ delay, duration: 0.6 }}
    className="glass-card hover:border-primary-500/50 group"
  >
    <div className="w-16 h-16 bg-primary-600/10 rounded-2xl flex items-center justify-center mb-6 group-hover:bg-primary-600 group-hover:text-white transition-all duration-300 shadow-2xl">
      <Icon size={32} className="text-primary-400 group-hover:text-white transition-all" />
    </div>
    <h3 className="text-2xl font-black mb-4 uppercase tracking-tighter">{title}</h3>
    <p className="text-gray-400 leading-relaxed font-bold italic opacity-60 uppercase tracking-widest text-xs">
      {desc}
    </p>
  </motion.div>
);

export default Home;
